"""schedule.yaml serialization."""

from __future__ import annotations

import contextlib
import os
from pathlib import Path

import yaml

from planner.engine._types import ScheduleData

SCHEDULE_COMMENTS = {
    "summary": [
        "Generated by `uv run python -m planner`; edit source cards under data/, not this file.",
        "Short human-facing summary.",
        "`take` is grouped by pillbox so daily and training products do not read as one regimen.",
    ],
    "placement_notes": [
        "Non-warning placement compromises.",
        "These explain acceptable but imperfect slot choices; they are not safety warnings.",
    ],
    "pillboxes": [
        "Planned pillboxes and their intake slots.",
        "`products` lists scheduled product names; `substances` expands those products for human review.",
    ],
    "benefits": [
        "Benefit goal membership overview.",
        "`members` separates relevance, product tracking, and usage state; expert gaps are not inferred here.",
    ],
    "risks": [
        "Risk load membership overview.",
        "`members` separates relevance, product tracking, and usage state; expert severity is not inferred here.",
    ],
    "active_fact_index": [
        "Fact-first active-stack index for agents.",
        "Each entry is an existing substance knowledge fact projected to active products.",
        "This section is evidence only: no roles, rankings, recommendations, or generated questions.",
    ],
    "warnings": [
        "Detailed review warnings.",
        "Warnings are prompts for human review; they are not medical advice.",
    ],
    "kept_together": [
        "Product pairs the planner tried to place in the same slot.",
        "`together` says whether they landed together.",
    ],
    "explanations": [
        "Per-product placement explanation.",
        "`slot` is the chosen slot; `components` lists the product substances that drove scheduling.",
        "`why_here` summarizes why this slot was selected.",
        "`review_tags` are readable traits aggregated from the product substances.",
    ],
}


class NoAliasSafeDumper(yaml.SafeDumper):
    """Safe YAML dumper for human-facing generated output."""

    def ignore_aliases(self, data: object) -> bool:
        return True


def dump_schedule_yaml(schedule: ScheduleData) -> str:
    """Serialise schedule and inject comment blocks above top-level keys."""
    rendered = yaml.dump(
        schedule,
        Dumper=NoAliasSafeDumper,
        sort_keys=False,
        default_flow_style=False,
        allow_unicode=True,
    )
    lines: list[str] = []
    for line in rendered.splitlines():
        key = line.split(":", 1)[0] if line and not line.startswith(" ") else ""
        if key in SCHEDULE_COMMENTS:
            lines.extend(f"# {comment}" for comment in SCHEDULE_COMMENTS[key])
        lines.append(line)
    return "\n".join(lines) + "\n"


def write_schedule_file(schedule_file: Path, schedule: ScheduleData) -> None:
    """Atomically write the rendered schedule to disk."""
    tmp_schedule_file = schedule_file.with_name(f"{schedule_file.name}.tmp.{os.getpid():x}")
    try:
        tmp_schedule_file.write_text(dump_schedule_yaml(schedule), encoding="utf-8")
        tmp_schedule_file.replace(schedule_file)
    except OSError:
        with contextlib.suppress(OSError):
            tmp_schedule_file.unlink(missing_ok=True)
        raise


def schedule_slot_loads(schedule: ScheduleData) -> dict[str, int]:
    """Return product counts per pillbox slot."""
    return {
        f"{pillbox_name}.{slot_name}": len(slot_entry["products"])
        for pillbox_name, pillbox in schedule["pillboxes"].items()
        for slot_name, slot_entry in pillbox["slots"].items()
    }
